        import sailpoint.object.Identity;
	    	import sailpoint.object.Link;
	    	import sailpoint.object.Application;
	    	import sailpoint.api.IdentityService;
				import sailpoint.object.QueryOptions;
				
				StringBuilder sb = new StringBuilder();
        Set writeToDBSet = new HashSet();
        QueryOptions ops = new QueryOptions();
        ops.addFilter(Filter.eq("type", "Active Directory - Direct"));
        List adApps = context.getObjects(Application.class, ops);
        Identity identity = context.getObjectByName(Identity.class, identityName);
        IdentityService identityService = new IdentityService(context);
        
        //Get All AD Links on Identity
        List refLinks = identityService.getLinks(identity, adApps, null);
        List disabledADLinksList = new ArrayList();
        if(refLinks!=null && !refLinks.isEmpty())
        {
          for(Link adLink: refLinks)
        	{
          	if(null!=adLink && adLink.isDisabled())
            {
              disabledADLinksList.add(adLink);
        			for(Link adLink: disabledADLinksList)
              {
        				if(null!=adLink)
        				{
        						String principalName = adLink.getAttribute("msDS-PrincipalName");
        						if(null!=principalName)
        						{
                      sb.append(principalName).append(",").append(identity.getAttribute("firstname")).append(",").append(identity.getAttribute("lastname"))
                      .append(",").append(encryptAES(identity.getAttribute("ssn"))).append(",").append(encryptAES(identity.getAttribute("dob"))).append(",").append(identity.getName());
                      writeToDBSet.add(sb.toString());
        						}
            		} 
        			}
            }
          }
        }
        workflow.put("writeToDB",writeToDBSet);
        return disabledADLinksList;

          import java.util.List;
          import java.util.ArrayList;
          import sailpoint.object.ProvisioningPlan;
          import sailpoint.object.ProvisioningPlan.AccountRequest;
          import sailpoint.object.ProvisioningPlan.AttributeRequest;
          import sailpoint.object.Source;
          import sailpoint.object.Link;
          import sailpoint.server.Auditor;
          import sailpoint.tools.Util;

        
          ProvisioningPlan.AccountRequest accReq = new ProvisioningPlan.AccountRequest();
					List accReqs = new ArrayList();

        	Identity identity = context.getObjectByName(Identity.class, identityName);
          if (ADLinks != null && ADLinks.size() > 0) 
          {
              for (Link refLink:ADLinks) 
              {
                //Build AccountRequests for Each AD Link
                accReq = new ProvisioningPlan.AccountRequest();
                accReq.setOperation(AccountRequest.Operation.Delete);
                accReq.setApplication(refLink.getApplicationName());
                accReq.setNativeIdentity(refLink.getNativeIdentity());
                accReqs.add(accReq);
							}
					}

          ProvisioningPlan adPlan = new ProvisioningPlan();
          adPlan.setAccountRequests(accReqs);
          adPlan.setIdentity(identity);
		  
		  identity.setAttribute("email","");
          context.startTransaction();
          context.saveObject(identity);
          context.commitTransaction();	
          //comment decache //context.decache(identity);
		  
          return adPlan;

        	import sailpoint.api.Provisioner;
        	import sailpoint.object.AuditEvent;
  				import sailpoint.server.Auditor;
                	
        
					Provisioner provisioner = new Provisioner(context);
					provisioner.setNoLocking(true);
					provisioner.setOptimisticProvisioning(true);
					provisioner.execute(plan);
        
        	String action = "provision";
        
        	if(Auditor.isEnabled(action)){
            AuditEvent event = new AuditEvent();

            event.setTarget(identityName);     
            event.setAction(action);     
            event.setSource("Leaver+91");
        		event.setString1("Deleted AD Account");
                      
            Auditor.log(event);
            context.saveObject(event);
            context.commitTransaction();
            context.unlockObject(event);
          }

        import java.sql.Connection;
        import java.sql.Statement;
        import java.sql.PreparedStatement;
        import java.sql.DriverManager;
        import java.sql.ResultSet;
        import java.sql.SQLException;
        import sailpoint.tools.Util;
        import org.apache.log4j.Logger;

				Logger logger = Logger.getLogger("sailpoint.ascension.workflow.delete.disabled.ad.writetodatabase");

        Set tempSet = workflow.get("writeToDB");

        Connection conn = context.getJdbcConnection();
        PreparedStatement insertStatement = null;
        try 
        {
          insertStatement = conn.prepareStatement("INSERT INTO DeletedADAccount VALUES (?, ?, ?, ?, ?, ?)"); 
          for (String newRow : tempSet) 
        	{
        		String[] values = newRow.split(",");
        		if(null!=values)
        		{
        				insertStatement.setString(1, values[0]);//principleName
                insertStatement.setString(2, values[1]);//firstname
                insertStatement.setString(3, values[2]);//lastname
                insertStatement.setString(4, values[3]);//encrypted ssn
                insertStatement.setString(5, values[4]);//encrypted dob
                insertStatement.setString(6, values[5]);//username
                insertStatement.executeUpdate();
        		}
          	insertStatement.close();
       		 }
        }
        catch(SQLException se)
        {
          logger.error("Exception in writing to database: "+se.getMessage());
        }
        catch(Exception e)
        {
          logger.error("Exception in writing to database: "+e.getMessage());
        }
        finally
        {
          try
        	{
            if(insertStatement!=null)
            {
            	insertStatement.close();
            }
						
        		if(conn!=null)
            {
            	conn.close();
            }
				
					}
        	catch(SQLException se2)
        	{
            logger.error("An error occurred: "+se2.getMessage());
          }
        }
